import React from "react";
import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  return (
    <section style={{ padding: "40px" }}>
      {/* Popular Products */}
      <h2 style={{ textAlign: "center", marginBottom: "30px" }}>
        Popular Products
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)",
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item, index) => (
          <div key={item.id ?? item._id ?? index} style={{ textAlign: "left" }}>
            {/* Image box */}
            <div
              style={{
                border: "1px solid #ddd",
                padding: "29px",
                background: "#f1f1f6ff",
                height: "150px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <img
                src={item.image}
                alt={item.name}
                style={{
                  maxWidth: "100%",
                  maxHeight: "180px",
                  objectFit: "contain",
                }}
              />
            </div>

            {/* Product details */}
            <h3
              style={{
                fontSize: "14px",
                margin: "10px 0 5px",
                fontFamily: "'Poppins', sans-serif",
              }}
            >
              {item.name}
            </h3>
            <p style={{ fontWeight: "bold", margin: "5px 0" }}>${item.price}</p>

            {/* ✅ Ratings (5 stars + number) */}
            <div
              style={{
                display: "flex",
                justifyContent: "left",
                alignItems: "center",
                gap: "5px",
                marginTop: "5px",
              }}
            >
              <span style={{ color: "#ee6b19ff", fontSize: "10px" }}>⭐⭐⭐⭐⭐</span>
              <span style={{ fontSize: "13px", color: "#555" }}>{item.rating}</span>
            </div>

            <button
              style={{
                marginTop: "8px",
                padding: "8px 15px",
                border: "none",
                borderRadius: "6px",
                background: "#ff6d0cff",
                color: "#fff",
                cursor: "pointer",
              }}
            >
              Buy Now
            </button>
          </div>
        ))}
      </div>

      {/* Featured Picks Section */}
      <div style={{ marginTop: "60px" }}>
        <h2 style={{ textAlign: "center", marginBottom: "20px" }}>Featured Picks</h2>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(3, 1fr)",
            gap: "25px",
            maxWidth: "1000px",
            margin: "0 auto",
          }}
        >
          {[
            {
              title: "Unparalleled Sound",
              desc: "Experience crystal-clear audio with premium headphones.",
              img: "/images/products/feature1.jpg",
            },
            {
              title: "Stay Connected",
              desc: "Compact and stylish earphones for every occasion.",
              img: "/images/products/feature3.jpg",
            },
            {
              title: "Power in Every Pixel",
              desc: "Shop the latest laptops for work, gaming, and more.",
              img: "/images/products/feature5.jpg",
            },
          ].map((card, idx) => (
            <div
              key={idx}
              style={{
                position: "relative",
                height: "370px",
                backgroundImage: url('${card.img}'),
                backgroundSize: "cover",
                backgroundPosition: "center",
                display: "flex",
                alignItems: "flex-end",
                color: "#fff",
              }}
            >
              <div style={{ padding: "15px", width: "100%" }}>
                <h3 style={{ margin: "0 0 10px" }}>{card.title}</h3>
                <p style={{ fontSize: "14px", marginBottom: "10px" }}>{card.desc}</p>
                <button
                  style={{
                    padding: "8px 15px",
                    border: "none",
                    background: "#9d5b2e",
                    color: "#fff",
                    cursor: "pointer",
                  }}
                >
                  Buy Now ↗
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Gaming Banner Section */}
      <div
        style={{
          marginTop: "60px",
          background: "#cdd0e5ff",
          padding: "50px 40px",
          borderRadius: "16px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          maxWidth: "1200px",
          marginLeft: "auto",
          marginRight: "auto",
        }}
      >
        <img src="/images/products/jbl.webp" alt="Speaker" style={{ width: "220px", objectFit: "contain" }} />

        <div style={{ textAlign: "center", flex: 1 }}>
          <h2
            style={{
              fontSize: "28px",
              fontWeight: "700",
              marginBottom: "10px",
              color: "#30425aff",
            }}
          >
            Level Up Your <br /> Gaming Experience
          </h2>
          <p style={{ color: "#4b5563", fontSize: "16px", marginBottom: "20px" }}>
            From immersive sound to precise controls — everything you need to win.
          </p>
          <button
            style={{
              padding: "10px 20px",
              border: "none",
              borderRadius: "6px",
              background: "#f05a28",
              color: "#fff",
              fontSize: "14px",
              cursor: "pointer",
            }}
          >
            Buy Now →
          </button>
        </div>

        <img src="/images/products/controller1.png" alt="Controller" style={{ width: "220px", objectFit: "contain" }} />
      </div>

      {/* Subscribe Section */}
      <div style={{ marginTop: "80px", padding: "50px 20px", background: "#f4f4f4", textAlign: "center" }}>
        <h2 style={{ marginBottom: "15px" }}>📩 Subscribe now & get 20% off </h2>
        <p style={{ marginBottom: "20px", color: "#555" }}>Stay updated with the latest deals and new arrivals!</p>
        <form style={{ display: "flex", justifyContent: "center", maxWidth: "500px", margin: "0 auto" }}>
          <input
            type="email"
            placeholder="Enter your email"
            required
            style={{ padding: "12px", flex: 1, border: "1px solid #ccc", borderRadius: "6px 0 0 6px" }}
          />
          <button
            type="submit"
            style={{ padding: "12px 20px", border: "none", background: "#9d5b2e", color: "#fff", borderRadius: "0 6px 6px 0", cursor: "pointer" }}
          >
            Subscribe
          </button>
        </form>
      </div>
    </section>
  );
};

export default PopularProducts;
